e:"Copy Recipe",copied:"Copied!",emptyStateTitle:"Enter your flour amounts above to calculate your recipe.",emptyStateSubtitle:"The calculator updates automatically as you type.",footerLine1:"Sourdough Calculator — open source, runs entirely in your browser.",footerLine2:"All calculations are guidelines. Your dough knows best.",copyTitle:"🍞 SOURDOUGH RECIPE",copyDivider:"===================",copyScheduleHeader:"SCHEDULE",copyScheduleDivider:"--------",copyAssumptionsHeader:"ASSUMPTIONS",copyAssumptionsDivider:"-----------",copyFooter:"Generated by DoughCulator",parameters:"Parameters",kitchenTemp:"Kitchen temp",temperatures:"Temperatures",bakingProfile:"Baking Profile",fineTuning:"Fine Tuning",totalFlour:"Total Flour (g)",flourSelection:"Flour Selection",flourTypes:{BreadFlour:"Bread Flour",AllPurpose:"All-Purpose",WholeWheat:"Whole Wheat",Rye:"Rye",Spelt:"Spelt",Einkorn:"Einkorn"},blendTotal:"Total",blendNormalize:"Normalize to 100%",flourBlend:"Flour Blend",crumbGoal:"Crumb Goal",crumbGoalNames:{Tight:"Tight",Balanced:"Balanced",Open:"Open"},crumbDescriptions:{Tight:"Dense, uniform bubbles. Best for toast & sandwiches.",Balanced:"Medium bubbles, versatile crumb. Classic sourdough.",Open:"Large holes, translucent walls. Advanced technique required."},advancedOptions:"Advanced Options",ambientTemp:"Ambient Temperature",doughTemp:"Dough Temperature",optional:"— optional",leaveBlankAmbient:"Leave blank to use ambient",salt:"Salt",saltAutoLabel:(a,n)=>`Auto: ${a}% = ${n}g`,saltManual:"Manual",saltOverride:"Override",saltBakersPct:"Baker's % relative to total flour",starterHydration:"Starter Hydration (%)",starterHydrationDefaultLabel:"Default: 100%",starterHydrationManual:"Manual",starterHydrationOverride:"Override",autolyse:"Autolyse",off:"Off",auto:"Auto",duration:"Duration",autolyseModalTitle:"Autolyse Guide",autolyseModalIntro:"Autolyse is a short rest after mixing flour and water, before adding starter and salt. It improves hydration and starts gluten development with less mixing.",autolyseModalUseTitle:"When to use it",autolyseModalUseItems:["High-hydration doughs where you want better extensibility and easier shaping.","Doughs with whole wheat or thirsty flours that benefit from fuller hydration.","When the dough feels tight during mixing and you want gentler gluten development."],autolyseModalAvoidTitle:"When to skip or shorten",autolyseModalAvoidItems:["Very warm kitchen or dough conditions (around 29°C / 84°F and above); keep it short or leave it off.","If your dough already gets slack or sticky quickly; long autolyse can reduce strength.","When you need a fast mix-and-go workflow and prefer speed over marginal handling gains."],fermentationPhilosophyLabel:"Fermentation Philosophy",philosophyPredictability:"Predictability",philosophyFlavorDev:"Flavor Development",philosophyPredictabilityDesc:"More starter when cold — consistent timing.",philosophyFlavorDevDesc:"Less starter when cold — slower fermentation builds complexity.",philosophyModalTitle:"Fermentation Philosophy",philosophyModalPredictabilityBody:"Predictability uses a higher inoculation rate when temperatures drop. This keeps fermentation on a reliable schedule regardless of season or kitchen conditions — ideal when you want consistent results and a repeatable bake-day routine.",philosophyModalFlavorDevBody:"Flavor Development lowers inoculation in cold conditions, letting the dough ferment slowly over a longer window. Extended time produces more acetic and lactic acids, yielding a more complex, tangy flavor — great for cold retard bakes or when you can be flexible with timing.",proofMethod:"Proof Method",proofMethodModalTitle:"Proof Methods",proofMethodRoomBody:"Room temperature proofing lets your shaped dough rise at ambient temperature. It's faster (typically 1–3 hours) and produces a milder flavor. Watch the dough closely — it can over-proof quickly in a warm kitchen.",proofMethodColdRetardBody:"Cold retard places your shaped dough in the fridge (typically 8–16 hours overnight). The slow, cold fermentation develops more complex, tangy flavors and gives you a flexible baking window — pull it out when you're ready to bake.",roomTemp:"Room Temp",coldRetard:"Cold Retard",fridgeTemp:"Fridge Temperature",scheduleMode:"Schedule Mode",relative:"Relative",clock:"Clock",startTime:"Start Time (HH:MM)",formulaInfoTitle:"Understanding Your Formula",formulaInfoMixBody:`"What You Add" shows the amounts you physically measure and mix — flour, water, starter, and salt. The flour and water here exclude what's already inside your starter.`,formulaInfoFormulaBody:`The "Full Baker's Formula" shows total flour and water in the entire dough, including the flour and water contributed by your starter. Baker's percentages are always calculated relative to this total flour — that's why the flour amount here is higher than what you physically add.`,formula:"Formula",bakersPctSubtitle:"Baker's percentages relative to total flour",ingredient:"Ingredient",grams:"Grams",bakersPct:"Baker's %",totalFlourRow:"Total Flour",whiteFlouRow:"— White flour",wwFlourRow:"— Whole wheat",water:"Water",saltRow:"Salt",starter:"Starter",totalDough:"Total Dough",doughWeight:"Dough weight",starterBreakdown:"Starter Breakdown",starterFlour:"Starter flour",starterWater:"Starter water",totalStarter:"Total starter",mixAdditions:"What You Add",bakersFormula:"Baker's Formula",fullFormula:"Full Baker's Formula",totalFlourBasis:"Total flour (basis)",mixFlour:"Flour",mixWater:"Water",starterNote:"Starter flour/water is already counted in total formula above.",starterContains:(a,n,d)=>`Starter contains ${a}g flour + ${n}g water (ratio ${d})`,timing:"Timing",bulkFermentation:"Bulk Fermentation",timingBarsModalTitle:"Timing Bar Guide",timingBarsModalIntro:"These bars show a fermentation window, not one exact minute. Read them left to right: the darker inner bar marks the earliest likely ready point, and the lighter bar behind it shows the later end of the recommended range.",timingBarsBulkTitle:"Bulk Fermentation",timingBarsBulkBody:"When the darker bar ends, start checking the dough for rise, bubbles, and jiggle. If it still needs time, let it continue toward the end of the lighter bar.",timingBarsColdTitle:"Cold Retard",timingBarsColdBody:"For cold retard, the darker fill marks the earliest bake-ready point after chilling. The lighter full bar shows the longer holding window in the fridge before the dough risks going too far.",fastest:"Fastest",slowest:"Slowest",foldSchedule:(a,n)=>`${a} stretch-and-fold sets, every ${n} min`,roomProof:"Room Proof",coldRetardProof:"Cold Retard",bakeColdNote:"Can bake directly from fridge.",totalActiveTime:"Estimated total active time (excl. bake):",inoculation:"Inoculation",hydration:"Hydration",schedule:"Schedule",notesWarnings:"Notes & Warnings",readingYourCrumb:"Reading Your Crumb",target:a=>`Target (${a}):`,underFermented:"Under-fermented:",overFermented:"Over-fermented:",guidance:{Tight:{description:"Dense but moist interior, small uniform bubbles.",underFermented:"Gummy center, flat rise, pale crust.",overFermented:"Bitter flavor, dense with no oven spring."},Balanced:{description:"Mix of small and medium bubbles, even distribution.",underFermented:"Dense patches, brick-like texture on the bottom.",overFermented:"Large irregular holes with weak structure, shaggy crumb."},Open:{description:"Large irregular holes, translucent bubble walls — requires high skill.",underFermented:"Closed crumb despite high hydration, no bloom.",overFermented:"Flat, gummy, shredded crumb with sour overload."}},floatTest:"Float test:",floatTestDesc:"The float test checks if your starter/levain is ready — a spoonful of ripe starter should float in water. This test is for starter readiness, not bulk dough.",pokeTest:"Poke test:",pokeTestDesc:"Poke proofed dough — slow, partial spring-back = ready to bake.",jiggleTest:"Jiggle test:",jiggleTestDesc:"Shake container — dough should move like jello when bulk is complete.",calcula